env['ir.config_parameter'].sudo().set_param('maintenance.status', 'on')
env['ir.config_parameter'].sudo().set_param('maintenance.start_time', str(datetime.datetime.now()))

action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': '🔴 Đã bật bảo trì',
        'message': 'Hệ thống đã chuyển sang chế độ bảo trì',
        'type': 'warning',
        'sticky': False,
    }
}

